package com.JavaOperator;

public class ArthimeticOperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int m = 5;
		int n = 2;
		int result = m+n;
		
		System.out.println("m+n = " + result);
		
		result = m-n;
		
System.out.println("m-n = " + result);
		
		result = m*n;
		
System.out.println("m*n = " + result);
		
		result = m/n;
		
System.out.println("m/n = " + result);
		
		result = m%n;
		
System.out.println("m%n = " + result);
		

	}

}
